	function makeallchildrentransparent(node) {
	
	    for (var i = 0; i < node.childNodes.length; i++) {
	      var child = node.childNodes[i];
	      makeallchildrentransparent(child);
	      if (child.style)
	    	  child.style.background='transparent';;
	    }

	}
